content.query:
let hostEvents = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where Message has_any ("lost connection to the host", "hostshutdownevent", "hostaddedevent", "hostconnectedevent", "hostdisconnectedevent", "HostConnectionLostEvent")
| summarize Count = count()
| extend Event = "Host Events";
let vmDisconnected = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where Message has "vmdisconnectedevent"
| summarize Count = count()
| extend Event = "VM Disconnected";
let vmDeleted = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where Message has "vmremovedevent"
| summarize Count = count()
| extend Event = "VM Removed from Inventory";
let vmReboot = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where Message has "VmGuestRebootEvent"
| summarize Count = count()
| extend Event = "VM Guest Reboot";
let dnsFailures = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where AppName == "dnsmasq" and Message has "Failed DNS Query"
| summarize Count = count()
| extend Event = "DNS Failures";
let fwBlocked = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where (AppName == "FIREWALL" or ProcId == "FIREWALL") and Message has_any ("DROP", "REJECT", "denied")
| summarize Count = count()
| extend Event = "Firewall Blocked";
let maintenance = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where Message has_any ("The host has entered maintenance mode", "The host has exited maintenance mode")
| summarize Count = count()
| extend Event = "Host Maintenance Mode";
let roleChange = union isfuzzy=true AVSSyslog, (datatable(TimeGenerated:datetime, HostName:string, AppName:string, Facility:string, Severity:string, Message:string, ProcId:string)[])
| where TimeGenerated {TimeRange}
| where '*' in ({HostFilter}) or HostName in~ ({HostFilter})
| where Message has_any ("RoleAddedEvent", "RoleUpdatedEvent", "RoleRemovedEvent", "PermissionAddedEvent", "PermissionUpdatedEvent", "PermissionRemovedEvent")
| summarize Count = count()
| extend Event = "Role Changes";
union hostEvents, vmDisconnected, vmDeleted, vmReboot, dnsFailures, fwBlocked, maintenance, roleChange
| project Event, Count
| order by Count desc
